{
  "name": "EKSATHE",
  "description": "A modern social utility platform for finding companions for activities, ride sharing, and events. Featuring a clean UI and smart plan suggestions."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ActivityType {
  GAME = 'Game',
  RIDE_SHARE = 'Ride Share',
  HANGOUT = 'Hangout',
  STUDY = 'Study',
  EVENT = 'Event',
  OTHER = 'Other'
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
}

export interface Plan {
  id: string;
  userId: string;
  userName: string;
  type: ActivityType;
  title: string;
  description: string;
  location: string;
  from?: string;
  to?: string;
  dateTime: string;
  createdAt: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getPlanEnhancements = async (title: string, description: string) => {
  if (!process.env.API_KEY) return "Login to use AI enhancements.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `I am planning an activity: "${title}". Description: "${description}". Give me 3 creative catchphrases or icebreakers to include in my post to attract more companions. Keep them short and friendly.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || "[]") as string[];
  } catch (error) {
    console.error("Gemini Error:", error);
    return ["Let's make some memories together!", "Join in for a great time!", "The more the merrier!"];
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-2.5 rounded-xl font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2";

  const variants = {
    primary: "bg-orange-500 text-white hover:bg-orange-600 focus:ring-orange-400",
    secondary: "bg-blue-500 text-white hover:bg-blue-600 focus:ring-blue-400",
    outline: "border-2 border-orange-500 text-orange-600 hover:bg-orange-50 focus:ring-orange-400",
    ghost: "text-gray-600 hover:bg-gray-100 focus:ring-gray-300"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
