  return (
    <div 
      className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow cursor-pointer group"
      onClick={onClick}
    >
      <div className="flex justify-between items-start mb-4">
        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${ACTIVITY_COLORS[plan.type]}`}>
          {plan.type}
        </span>
        <span className="text-gray-400 text-xs">
          {new Date(plan.createdAt).toLocaleDateString()}
        </span>
      </div>

      <h3 className="text-xl font-bold text-gray-800 mb-2 group-hover:text-orange-500 transition-colors">
        {plan.title}
      </h3>

      <p className="text-gray-600 text-sm mb-4 line-clamp-2">
        {plan.description}
      </p>

      {isRideShare && plan.from && plan.to && (
        <div className="mb-4 flex items-center gap-2 text-sm text-gray-500 bg-blue-50 p-3 rounded-lg">
          <span className="font-semibold text-blue-600">{plan.from}</span>
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
          </svg>
          <span className="font-semibold text-blue-600">{plan.to}</span>
        </div>
      )}

      <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-50">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-orange-100 flex items-center justify-center text-orange-600 font-bold text-xs uppercase">
            {plan.userName.charAt(0)}
          </div>
          <div>
            <p className="text-xs font-semibold text-gray-700">{plan.userName}</p>
            <p className="text-[10px] text-gray-400">{plan.location}</p>
          </div>
        </div>
        <div className="text-right">
          <p className="text-xs text-gray-400">Scheduled for</p>
          <p className="text-xs font-bold text-gray-700">
            {new Date(plan.dateTime).toLocaleDateString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
          </p>
        </div>
