};

import React, { useState, useMemo } from 'react';
import { Plan, ActivityType } from '../types';
import { Card } from '../components/Card';
import { MOCK_PLANS } from '../constants';

export const Find: React.FC = () => {
  const [filter, setFilter] = useState<ActivityType | 'ALL'>('ALL');
  const [search, setSearch] = useState('');

  const filteredPlans = useMemo(() => {
    return MOCK_PLANS.filter(plan => {
      const matchesFilter = filter === 'ALL' || plan.type === filter;
      const matchesSearch = plan.title.toLowerCase().includes(search.toLowerCase()) || 
                          plan.description.toLowerCase().includes(search.toLowerCase()) ||
                          plan.location.toLowerCase().includes(search.toLowerCase());
      return matchesFilter && matchesSearch;
    });
  }, [filter, search]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <div className="mb-12">
        <h1 className="text-4xl font-black text-slate-900 dark:text-white mb-4">Find Your Crew</h1>
        <p className="text-slate-600 dark:text-slate-400">Browse and join plans that interest you.</p>
      </div>

      <div className="flex flex-col md:flex-row gap-6 mb-10">
        <div className="flex-1">
          <div className="relative group">
            <input
              type="text"
              placeholder="Search by activity, city or keywords..."
              className="w-full pl-12 pr-4 py-4 rounded-2xl border border-gray-200 dark:border-slate-700 focus:outline-none focus:ring-2 focus:ring-orange-400 bg-white dark:bg-slate-800 text-slate-900 dark:text-white transition-all"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-400 group-focus-within:text-orange-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
        </div>
        <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
          <button
            onClick={() => setFilter('ALL')}
            className={`px-6 py-4 rounded-2xl font-bold whitespace-nowrap transition-all shadow-sm ${
              filter === 'ALL' ? 'bg-orange-500 text-white' : 'bg-white dark:bg-slate-800 text-gray-600 dark:text-slate-400 border border-gray-100 dark:border-slate-700 hover:border-orange-200 dark:hover:border-slate-600'
            }`}
          >
            All Plans
          </button>
          {Object.values(ActivityType).map(type => (
            <button
              key={type}
              onClick={() => setFilter(type)}
              className={`px-6 py-4 rounded-2xl font-bold whitespace-nowrap transition-all shadow-sm ${
                filter === type ? 'bg-orange-500 text-white' : 'bg-white dark:bg-slate-800 text-gray-600 dark:text-slate-400 border border-gray-100 dark:border-slate-700 hover:border-orange-200 dark:hover:border-slate-600'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </div>

      {filteredPlans.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredPlans.map(plan => (
            <Card key={plan.id} plan={plan} />
          ))}
        </div>
      ) : (
        <div className="text-center py-24 bg-white dark:bg-slate-800 rounded-3xl border border-dashed border-gray-200 dark:border-slate-700">
          <div className="text-6xl mb-4">🔍</div>
          <h3 className="text-2xl font-bold text-slate-800 dark:text-white">No matching plans found</h3>
          <p className="text-slate-500 dark:text-slate-400 mt-2">Try adjusting your filters or search keywords.</p>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ActivityType, User } from '../types';
import { Button } from '../components/Button';
import { getPlanEnhancements } from '../services/geminiService';

interface PostProps {
  user: User | null;
  onAddPlan: (plan: any) => void;
}

export const Post: React.FC<PostProps> = ({ user, onAddPlan }) => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    type: ActivityType.HANGOUT,
    title: '',
    description: '',
    location: '',
    from: '',
    to: '',
    dateTime: '',
  });
  const [loading, setLoading] = useState(false);
  const [aiSuggestions, setAiSuggestions] = useState<string[]>([]);
  const [suggesting, setSuggesting] = useState(false);

  if (!user) {
    return (
      <div className="max-w-md mx-auto py-24 text-center px-4">
        <div className="text-5xl mb-6">🔒</div>
        <h2 className="text-2xl font-bold mb-4 text-slate-900 dark:text-white">Sign in to post a plan</h2>
        <p className="text-slate-500 dark:text-slate-400 mb-8">Join the community to start connecting with others for your activities.</p>
        <Button fullWidth onClick={() => navigate('/login')}>Login Now</Button>
      </div>
    );
  }

  const handleGetSuggestions = async () => {
    if (!formData.title || !formData.description) return;
    setSuggesting(true);
    const suggestions = await getPlanEnhancements(formData.title, formData.description);
    setAiSuggestions(suggestions);
    setSuggesting(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const newPlan = {
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      createdAt: new Date().toISOString(),
    };

    setTimeout(() => {
      onAddPlan(newPlan);
      setLoading(false);
      navigate('/find');
    }, 1000);
  };

  const inputClasses = "w-full p-4 rounded-xl border border-gray-200 dark:border-slate-700 focus:ring-2 focus:ring-orange-400 outline-none bg-gray-50 dark:bg-slate-700 text-slate-900 dark:text-white transition-all";

  return (
    <div className="max-w-3xl mx-auto px-4 py-12">
      <div className="bg-white dark:bg-slate-800 rounded-3xl p-8 shadow-xl border border-gray-100 dark:border-slate-700 transition-colors">
        <h1 className="text-3xl font-black text-slate-900 dark:text-white mb-8">Post a Plan</h1>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Activity Type</label>
              <select
                className={inputClasses}
                value={formData.type}
                onChange={(e) => setFormData({...formData, type: e.target.value as ActivityType})}
                required
              >
                {Object.values(ActivityType).map(type => (
                  <option key={type} value={type} className="dark:bg-slate-800">{type}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">When</label>
              <input
                type="datetime-local"
                className={inputClasses}
                value={formData.dateTime}
                onChange={(e) => setFormData({...formData, dateTime: e.target.value})}
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Title</label>
            <input
              type="text"
              placeholder="e.g. Cricket match this Sunday"
              className={inputClasses}
              value={formData.title}
              onChange={(e) => setFormData({...formData, title: e.target.value})}
              required
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Description</label>
            <textarea
              rows={4}
              placeholder="Describe your plan. What are you looking for?"
              className={`${inputClasses} resize-none`}
              value={formData.description}
              onChange={(e) => setFormData({...formData, description: e.target.value})}
              required
            />
          </div>

          {formData.type === ActivityType.RIDE_SHARE ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">From</label>
                <input
                  type="text"
                  placeholder="Starting point"
                  className={inputClasses}
                  value={formData.from}
                  onChange={(e) => setFormData({...formData, from: e.target.value})}
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">To</label>
                <input
                  type="text"
                  placeholder="Destination"
                  className={inputClasses}
                  value={formData.to}
                  onChange={(e) => setFormData({...formData, to: e.target.value})}
                  required
                />
              </div>
            </div>
          ) : (
            <div>
              <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Location</label>
              <input
                type="text"
                placeholder="Meeting point or area"
                className={inputClasses}
                value={formData.location}
                onChange={(e) => setFormData({...formData, location: e.target.value})}
                required
              />
            </div>
          )}

          {/* AI Helper Section */}
          <div className="bg-orange-50 dark:bg-orange-900/20 p-6 rounded-2xl border border-orange-100 dark:border-orange-900/40">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-2">
                <span className="text-xl">✨</span>
                <span className="font-bold text-orange-800 dark:text-orange-300">AI Plan Helper</span>
              </div>
              <button 
                type="button"
                onClick={handleGetSuggestions}
                disabled={suggesting || !formData.title}
                className="text-sm font-bold text-orange-600 dark:text-orange-400 hover:text-orange-700 disabled:opacity-50"
              >
                {suggesting ? 'Thinking...' : 'Get Catchy Phrases'}
              </button>
            </div>
            {aiSuggestions.length > 0 ? (
              <div className="space-y-2">
                {aiSuggestions.map((s, idx) => (
                  <div 
                    key={idx} 
                    className="bg-white dark:bg-slate-800 p-3 rounded-xl text-sm text-slate-700 dark:text-slate-300 border border-orange-200 dark:border-orange-800 cursor-pointer hover:bg-orange-100 dark:hover:bg-slate-700 transition-colors shadow-sm"
                    onClick={() => setFormData({...formData, description: formData.description + " " + s})}
                  >
                    {s} <span className="text-xs text-orange-400 dark:text-orange-500 ml-2 font-medium">(Add)</span>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-xs text-orange-400 dark:text-orange-500/80">Add a title and description, then click to get AI-powered icebreakers to attract more people!</p>
            )}
          </div>

          <Button type="submit" fullWidth disabled={loading} className="py-4 shadow-lg shadow-orange-500/20">
            {loading ? 'Posting...' : 'Create My Plan'}
          </Button>
        </form>
      </div>
    </div>
  );
};

