import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate, Link } from 'react-router-dom';
import { Navbar } from './components/Navbar';
import { Home } from './pages/Home';
import { Find } from './pages/Find';
import { Post } from './pages/Post';
import { RideShare } from './pages/RideShare';
import { Auth } from './pages/Auth';
import { Dashboard } from './pages/Dashboard';
import { User, Plan } from './types';
import { MOCK_PLANS } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [plans, setPlans] = useState<Plan[]>(MOCK_PLANS);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('eksathe_theme') === 'dark';
  });

  useEffect(() => {
    const savedUser = localStorage.getItem('eksathe_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('eksathe_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('eksathe_theme', 'light');
    }
  }, [darkMode]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('eksathe_user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eksathe_user');
  };

  const handleAddPlan = (newPlan: Plan) => {
    setPlans([newPlan, ...plans]);
  };

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const userPlans = plans.filter(p => p.userId === user?.id);

  return (
    <Router>
      <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 flex flex-col transition-colors duration-300">
        <Navbar 
          user={user} 
          onLogout={handleLogout} 
          darkMode={darkMode} 
          toggleDarkMode={toggleDarkMode} 
        />

        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/find" element={<Find />} />
            <Route 
              path="/post" 
              element={<Post user={user} onAddPlan={handleAddPlan} />} 
            />
            <Route path="/ride-share" element={<RideShare />} />
            <Route 
              path="/login" 
              element={user ? <Navigate to="/dashboard" /> : <Auth onLogin={handleLogin} />} 
            />
            <Route 
              path="/dashboard" 
              element={<Dashboard user={user} userPlans={userPlans} />} 
            />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <footer className="bg-white dark:bg-slate-800 border-t border-gray-100 dark:border-slate-700 py-12 mt-auto transition-colors">
          <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-4 gap-8">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-2 mb-4">
                <div className="bg-orange-500 p-1.5 rounded-lg">
                  <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                  </svg>
                </div>
                <span className="text-xl font-black text-orange-600 dark:text-orange-500">EKSATHE</span>
              </div>
              <p className="text-gray-500 dark:text-slate-400 max-w-sm">
                Empowering communities to connect, share, and grow together. Not alone, but together.
              </p>
            </div>
            <div>
              <h4 className="font-bold text-gray-800 dark:text-slate-200 mb-4 text-lg">Platform</h4>
              <ul className="space-y-2 text-gray-500 dark:text-slate-400 text-sm">
                {/* Fixed: Link component now correctly imported */}
                <li><Link to="/find" className="hover:text-orange-500">Find Companions</Link></li>
                <li><Link to="/ride-share" className="hover:text-orange-500">Ride Sharing</Link></li>
                <li><Link to="/post" className="hover:text-orange-500">Post a Plan</Link></li>
              </ul>
            </div>
