          <p className="text-slate-500 dark:text-slate-400 font-medium">Fill in the details to find the perfect companions.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className={labelClasses}>Select Activity Type</label>
              <div className="relative">
                <select
                  className={`${inputClasses} appearance-none cursor-pointer`}
                  value={formData.type}
                  onChange={(e) => setFormData({...formData, type: e.target.value as ActivityType})}
                  required
                >
                  {Object.values(ActivityType).map(type => (
                    <option key={type} value={type} className="dark:bg-slate-800">{type}</option>
                  ))}
                </select>
                <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </div>
              </div>
            </div>
            <div className="space-y-2">
              <label className={labelClasses}>When is it happening?</label>
              <div className="relative group">
                <input
                  type="datetime-local"
                  className={inputClasses}
                  value={formData.dateTime}
                  onChange={(e) => setFormData({...formData, dateTime: e.target.value})}
                  required
                />
                <div className="absolute left-5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400 hidden group-focus-within:block">
                  {/* Styling the date input icon can be browser-specific, but the wrapper helps positioning */}
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className={labelClasses}>Catchy Title</label>
            <input
              type="text"
              placeholder="e.g. Friendly Cricket Match at Dhanmondi"
              className={inputClasses}
              value={formData.title}
              onChange={(e) => setFormData({...formData, title: e.target.value})}
              required
            />
          </div>

          <div className="space-y-2">
            <label className={labelClasses}>Tell us more</label>
            <textarea
              rows={4}
              placeholder="What's the plan? Any requirements or specific things people should know?"
              className={`${inputClasses} resize-none min-h-[150px]`}
              value={formData.description}
              onChange={(e) => setFormData({...formData, description: e.target.value})}
              required
            />
          </div>

          {formData.type === ActivityType.RIDE_SHARE ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-top-2 duration-300">
              <div className="space-y-2">
                <label className={labelClasses}>From Location</label>
                <input
                  type="text"
                  placeholder="Where are you starting?"
                  className={inputClasses}
                  value={formData.from}
                  onChange={(e) => setFormData({...formData, from: e.target.value})}
                  required
                />
              </div>
              <div className="space-y-2">
                <label className={labelClasses}>To Location</label>
                <input
                  type="text"
                  placeholder="Where are you going?"
                  className={inputClasses}
                  value={formData.to}
                  onChange={(e) => setFormData({...formData, to: e.target.value})}
                  required
                />
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <label className={labelClasses}>Meeting Point</label>
              <input
                type="text"
                placeholder="Where should everyone meet?"
                className={inputClasses}
                value={formData.location}
                onChange={(e) => setFormData({...formData, location: e.target.value})}
                required
              />
            </div>
          )}

          {/* AI Helper Section */}
          <div className="bg-brand-50/50 dark:bg-brand-900/10 p-8 rounded-[2rem] border border-brand-100 dark:border-brand-900/30 transition-all">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center gap-3">
                <span className="text-2xl animate-pulse">✨</span>
                <span className="font-extrabold text-brand-800 dark:text-brand-300 tracking-tight">AI Content Helper</span>
              </div>
              <button 
                type="button"
                onClick={handleGetSuggestions}
                disabled={suggesting || !formData.title}
                className="text-xs font-black uppercase tracking-widest text-brand-600 dark:text-brand-400 hover:text-brand-700 disabled:opacity-30 bg-white dark:bg-slate-800 px-4 py-2 rounded-full border border-brand-100 dark:border-brand-800 shadow-sm transition-all active:scale-95"
              >
                {suggesting ? 'Thinking...' : 'Polish my post'}
              </button>
            </div>
            {aiSuggestions.length > 0 ? (
              <div className="grid grid-cols-1 gap-3">
                {aiSuggestions.map((s, idx) => (
                  <div 
                    key={idx} 
                    className="bg-white/80 dark:bg-slate-800/80 p-4 rounded-2xl text-sm text-slate-700 dark:text-slate-300 border border-brand-200 dark:border-brand-800 cursor-pointer hover:border-brand-500 hover:bg-brand-50 dark:hover:bg-brand-900/20 transition-all shadow-sm active:scale-[0.99] group"
                    onClick={() => setFormData({...formData, description: formData.description ? formData.description + " " + s : s})}
                  >
                    <div className="flex justify-between items-center">
                      <span>{s}</span>
                      <span className="text-[10px] font-bold text-brand-500 opacity-0 group-hover:opacity-100 transition-opacity">TAP TO ADD</span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-xs text-brand-500 dark:text-brand-400/70 font-medium italic">Type a title and click polish to get AI-powered phrases to make your post stand out!</p>
            )}
          </div>

          <Button type="submit" fullWidth disabled={loading} className="py-6 rounded-2xl text-xl shadow-2xl shadow-brand-500/30 font-extrabold">
            {loading ? (
              <div className="flex items-center gap-3">
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Posting...
              </div>
            ) : 'Publish My Plan'}
          </Button>
        </form>
      </div>
    </div>
  );
};

