import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'glass';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-8 py-4 rounded-2xl font-extrabold transition-all duration-300 transform active:scale-95 flex items-center justify-center gap-3 tracking-tight select-none";

  const variants = {
    primary: "bg-brand text-white hover:bg-brand-dark hover:shadow-[0_8px_30px_rgb(255,92,0,0.4)] shadow-lg shadow-brand/20",
    secondary: "bg-slate-900 text-white dark:bg-white dark:text-slate-900 hover:opacity-90",
    outline: "border-2 border-brand text-brand hover:bg-brand hover:text-white",
    ghost: "text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800",
    glass: "glass-card text-slate-900 dark:text-white hover:shadow-xl border-white/40"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
