import React, { useState, useMemo } from 'react';
import { Plan, ActivityType } from '../types';
import { Card } from '../components/Card';
import { MOCK_PLANS } from '../constants';

export const Find: React.FC = () => {
  const [filter, setFilter] = useState<ActivityType | 'ALL'>('ALL');
  const [search, setSearch] = useState('');

  const filteredPlans = useMemo(() => {
    return MOCK_PLANS.filter(plan => {
      const matchesFilter = filter === 'ALL' || plan.type === filter;
      const matchesSearch = plan.title.toLowerCase().includes(search.toLowerCase()) || 
                          plan.description.toLowerCase().includes(search.toLowerCase()) ||
                          plan.location.toLowerCase().includes(search.toLowerCase());
      return matchesFilter && matchesSearch;
    });
  }, [filter, search]);

  return (
    <div className="max-w-7xl mx-auto px-6 py-32">
      <div className="mb-20 text-center">
        <h1 className="font-display text-5xl md:text-7xl font-black text-slate-900 dark:text-white mb-6 tracking-tighter italic uppercase">Discover Vibez</h1>
        <p className="text-slate-500 font-bold text-lg">Pick an activity and jump in.</p>
      </div>

      <div className="flex flex-col gap-8 mb-16">
        <div className="relative group">
          <input
            type="text"
            placeholder="Search by keyword, place, or activity..."
            className="w-full pl-16 pr-8 py-7 rounded-4xl border border-slate-200 dark:border-white/5 focus:ring-4 focus:ring-brand/20 outline-none glass-card dark:bg-dark-card text-slate-900 dark:text-white transition-all text-xl font-bold"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <svg className="absolute left-6 top-1/2 -translate-y-1/2 w-8 h-8 text-slate-400 group-focus-within:text-brand transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
        </div>

        <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
          <button
            onClick={() => setFilter('ALL')}
            className={`px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${
              filter === 'ALL' ? 'bg-brand text-white shadow-xl shadow-brand/30' : 'glass-card text-slate-500 hover:border-brand'
            }`}
          >
            All Moods
          </button>
          {Object.values(ActivityType).map(type => (
            <button
              key={type}
              onClick={() => setFilter(type)}
              className={`px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all whitespace-nowrap ${
                filter === type ? 'bg-brand text-white shadow-xl shadow-brand/30' : 'glass-card text-slate-500 hover:border-brand'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </div>

      {filteredPlans.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
          {filteredPlans.map(plan => (
            <Card key={plan.id} plan={plan} />
          ))}
        </div>
      ) : (
        <div className="text-center py-32 glass-card rounded-5xl border-dashed border-2 border-slate-200 dark:border-white/5">
          <div className="text-8xl mb-6">🏜️</div>
          <h3 className="text-3xl font-black text-slate-800 dark:text-white mb-2 italic">Ghost Town...</h3>
          <p className="text-slate-500 font-bold">Try searching for something else or post your own plan!</p>
        </div>
      )}
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'glass';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-3.5 rounded-2xl font-bold transition-all duration-200 active:scale-[0.97] flex items-center justify-center gap-2 tracking-tight select-none";

  const variants = {
    primary: "bg-brand-500 text-white hover:bg-brand-600 shadow-lg shadow-brand-500/20",
    secondary: "bg-slate-900 text-white dark:bg-white dark:text-slate-900 hover:opacity-90",
    outline: "border-2 border-brand-500 text-brand-600 dark:text-brand-500 hover:bg-brand-50 dark:hover:bg-brand-950/20",
    ghost: "text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800",
    glass: "glass-panel shadow-sm hover:shadow-md text-slate-900 dark:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

